import React, { useEffect, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import { explainError } from "./errorHelper";

function RunCodePage() {
  const location = useLocation();
  const navigate = useNavigate();
  const code = location.state?.code || "";

  const [output, setOutput] = useState("Running...");
  const [errorData, setErrorData] = useState(null);

  useEffect(() => {
    runCode();
  }, []);

  const runCode = async () => {
  try {
    const response = await fetch("https://emkc.org/api/v2/piston/execute", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        language: "javascript",
        version: "18.15.0",
        files: [{ content: code }],
      }),
    });

    const data = await response.json();

    // ✅ SAFETY CHECK
    if (!data.run) {
      setOutput("Error: Invalid API response");
      console.log("Full API response:", data); // DEBUG
      return;
    }

    const result = data.run;

    if (result.stderr && result.stderr.trim() !== "") {
      setOutput(result.stderr);
      setErrorData(explainError(result.stderr));
    } else {
      setOutput(result.stdout || "No Output");
      setErrorData(null);
    }

  } catch (error) {
    setOutput("Error: " + error.message);
  }
};
  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <button onClick={() => navigate("/")}>⬅ Back</button>
        <h2>Output (Piston)</h2>
      </div>

      <pre style={styles.output}>{output}</pre>

      {errorData && (
        <div style={styles.errorBox}>
          <h3>🧠 Samjho kya galat hua:</h3>
          <p><b>{errorData.message}</b></p>
          <p>{errorData.explanation}</p>

          <h4>✅ Kaise thik kare:</h4>
          <p>{errorData.fix}</p>
        </div>
      )}
    </div>
  );
}

const styles = {
  container: { background: "#1e1e1e", color: "#fff", height: "100vh", padding: "10px" },
  header: { display: "flex", gap: "10px", alignItems: "center" },
  output: { marginTop: "20px", background: "#000", padding: "15px", minHeight: "200px" },
  errorBox: { marginTop: "20px", padding: "15px", background: "#2d1e1e", border: "1px solid red" },
};

export default RunCodePage;
